/**
 * Memoria Design System Components
 * Premium dark-themed knowledge interfaces
 * 
 * STRICT RULES:
 * - No Emojis
 * - No Accent Colors (monochromatic only)
 * - No Gradients
 * - No Bold for Emphasis (size handles hierarchy)
 */

'use client';

import React, { useState } from 'react';
import { colors, fonts, typography, borderRadius, transitions, animations } from './tokens';

/**
 * Badge/Tag - Uppercase with subtle styling
 */
export function Badge({
  children,
  variant = 'default',
  className = '',
  style,
}: {
  children: React.ReactNode;
  variant?: 'default' | 'count' | 'type';
  className?: string;
  style?: React.CSSProperties;
}) {
  const variantStyles = {
    default: {
      background: colors.bg.neutral800,
      color: colors.text.neutral400,
      border: `1px solid ${colors.border.neutral700}`,
    },
    count: {
      background: colors.bg.neutral700,
      color: colors.text.neutral300,
    },
    type: {
      background: colors.bg.neutral800,
      color: colors.text.neutral400,
      border: `1px solid ${colors.border.neutral700}`,
      textTransform: 'uppercase',
      fontWeight: 600,
      letterSpacing: '0.05em',
    },
  };

  return (
    <span
      className={className}
      style={{
        ...variantStyles[variant],
        padding: '0.25rem 0.5rem',
        borderRadius: borderRadius.full,
        fontSize: '0.625rem', // 10px
        display: 'inline-flex',
        alignItems: 'center',
        ...style,
      }}
    >
      {children}
    </span>
  );
}

/**
 * Dark Card with subtle border and hover effect
 */
export function DarkCard({
  children,
  className = '',
  onClick,
  elevated = false,
}: {
  children: React.ReactNode;
  className?: string;
  onClick?: () => void;
  elevated?: boolean;
}) {
  const [isHovered, setIsHovered] = useState(false);

  return (
    <div
      onClick={onClick}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      className={className}
      style={{
        background: elevated ? colors.bg.neutral90080 : colors.bg.neutral90060,
        border: `1px solid ${isHovered ? colors.border.neutral700 : colors.border.neutral80060}`,
        borderRadius: borderRadius.lg,
        padding: '1rem',
        cursor: onClick ? 'pointer' : 'default',
        transition: 'all 0.3s ease-out',
        ...(isHovered && {
          background: colors.bg.neutral80060,
        }),
      }}
    >
      {children}
    </div>
  );
}

