/**
 * Minimal Button
 */
export function MinimalButton({
  children,
  onClick,
  variant = 'primary',
  size = 'md',
  className = '',
}: {
  children: React.ReactNode;
  onClick?: () => void;
  variant?: 'primary' | 'secondary' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  className?: string;
}) {
  const [isHovered, setIsHovered] = useState(false);

  const sizeMap = {
    sm: { padding: '0.5rem 1rem', fontSize: '0.75rem' },
    md: { padding: '0.75rem 1.5rem', fontSize: '0.875rem' },
    lg: { padding: '1rem 2rem', fontSize: '1rem' },
  };

  const variantStyles = {
    primary: {
      background: colors.bg.neutral800,
      border: `1px solid ${colors.border.neutral700}`,
      color: colors.text.white,
      ...(isHovered && {
        background: colors.bg.neutral700,
        borderColor: colors.border.neutral600,
      }),
    },
    secondary: {
      background: 'transparent',
      border: `1px solid ${colors.border.neutral800}`,
      color: colors.text.neutral400,
      ...(isHovered && {
        borderColor: colors.border.neutral700,
        color: colors.text.neutral200,
      }),
    },
    ghost: {
      background: 'transparent',
      border: 'none',
      color: colors.text.neutral500,
      ...(isHovered && {
        color: colors.text.neutral300,
      }),
    },
  };

  return (
    <button
      onClick={onClick}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      className={className}
      style={{
        ...sizeMap[size],
        ...variantStyles[variant],
        borderRadius: borderRadius.sm,
        cursor: 'pointer',
        transition: 'all 0.2s ease',
        fontFamily: fonts.body,
        fontWeight: 500,
      }}
    >
      {children}
    </button>
  );
}

/**
 * Icon Button (square)
 */
export function IconButton({
  icon,
  onClick,
  size = 'md',
  className = '',
}: {
  icon: React.ReactNode;
  onClick?: () => void;
  size?: 'sm' | 'md' | 'lg';
  className?: string;
}) {
  const [isHovered, setIsHovered] = useState(false);

  const sizeMap = {
    sm: '2rem',    // 32px
    md: '2.625rem', // 42px
    lg: '3rem',    // 48px
  };

  return (
    <button
      onClick={onClick}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      className={className}
      style={{
        width: sizeMap[size],
        height: sizeMap[size],
        background: colors.bg.neutral90080,
        border: `1px solid ${colors.border.neutral80060}`,
        borderRadius: borderRadius.md,
        color: isHovered ? colors.text.white : colors.text.neutral400,
        cursor: 'pointer',
        transition: 'all 0.2s ease',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
      }}
    >
      {icon}
    </button>
  );
}

/**
 * Text Input
 */
export function TextInput({
  placeholder,
  value,
  onChange,
  icon,
  className = '',
}: {
  placeholder?: string;
  value: string;
  onChange: (value: string) => void;
  icon?: React.ReactNode;
  className?: string;
}) {
  return (
    <div
      className={className}
      style={{
        position: 'relative',
        width: '100%',
      }}
    >
      {icon && (
        <div style={{
          position: 'absolute',
          left: '0.75rem',
          top: '50%',
          transform: 'translateY(-50%)',
          color: colors.text.neutral500,
        }}>
          {icon}
        </div>
      )}
      <input
        type="text"
        placeholder={placeholder}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        style={{
          width: '100%',
          padding: icon ? '0.75rem 1rem 0.75rem 2.5rem' : '0.75rem 1rem',
          background: colors.bg.neutral90080,
          border: `1px solid ${colors.border.neutral800}`,
          borderRadius: borderRadius.lg,
          color: colors.text.white,
          fontSize: '0.875rem',
          fontFamily: fonts.body,
          outline: 'none',
          transition: 'border-color 0.2s ease',
        }}
        onFocus={(e) => {
          e.target.style.borderColor = colors.border.neutral600;
        }}
        onBlur={(e) => {
          e.target.style.borderColor = colors.border.neutral800;
        }}
      />
    </div>
  );
}

/**
 * Progress Bar
 */
export function ProgressBar({
  percentage,
  label,
  className = '',
}: {
  percentage: number;
  label?: string;
  className?: string;
}) {
  return (
    <div className={className}>
      {label && (
        <div style={{
          display: 'flex',
          justifyContent: 'space-between',
          marginBottom: '0.5rem',
        }}>
          <span style={{
            ...typography.metadata,
          }}>
            {label}
          </span>
          <span style={{
            ...typography.metadata,
            color: colors.text.neutral400,
          }}>
            {percentage}%
          </span>
        </div>
      )}
      <div style={{
        height: '0.5rem',
        background: colors.bg.neutral800,
        borderRadius: borderRadius.full,
        overflow: 'hidden',
      }}>
        <div
          style={{
            height: '100%',
            width: `${percentage}%`,
            background: colors.bg.neutral700,
            borderRadius: borderRadius.full,
            transition: 'width 0.6s cubic-bezier(0.25, 0.1, 0.25, 1)',
          }}
        />
      </div>
    </div>
  );
}

/**
 * Empty State
 */
export function EmptyState({
  icon,
  title,
  description,
  action,
  className = '',
}: {
  icon: React.ReactNode;
  title: string;
  description?: string;
  action?: React.ReactNode;
  className?: string;
}) {
  return (
    <div
      className={className}
      style={{
        height: '100%',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        textAlign: 'center',
        padding: '1rem',
      }}
    >
      <div style={{
        width: '4rem',
        height: '4rem',
        background: colors.bg.neutral800,
        border: `1px solid ${colors.border.neutral700}`,
        borderRadius: borderRadius.lg,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        marginBottom: '1rem',
      }}>
        <div style={{ color: colors.text.neutral600 }}>
          {icon}
        </div>
      </div>
      <p style={{
        ...typography.body,
        color: colors.text.neutral400,
        fontSize: '1.125rem',
        fontWeight: 500,
        marginBottom: '0.5rem',
      }}>
        {title}
      </p>
      {description && (
        <p style={{
          ...typography.body,
          color: colors.text.neutral600,
          maxWidth: '24rem',
        }}>
          {description}
        </p>
      )}
      {action && (
        <div style={{ marginTop: '1.5rem' }}>
          {action}
        </div>
      )}
    </div>
  );
}

/**
 * Loading Spinner
 */
export function LoadingSpinner({
  size = 'md',
  className = '',
}: {
  size?: 'sm' | 'md' | 'lg';
  className?: string;
}) {
  const sizeMap = {
    sm: '1rem',
    md: '1.5rem',
    lg: '2rem',
  };

  return (
    <div
      className={className}
      style={{
        width: sizeMap[size],
        height: sizeMap[size],
        border: `2px solid ${colors.border.neutral800}`,
        borderTopColor: 'transparent',
        borderRadius: '50%',
        animation: 'spin 0.8s linear infinite',
      }}
    >
      <style jsx>{`
        @keyframes spin {
          to { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );
}
